// read/write sets, interpreted execution, and invariant conformance.

import { describe, it, expect, beforeEach } from 'vitest';
import fc from 'fast-check';
import { vueAdapterHandler } from '../../handlers/ts/app/vue-adapter.handler.js';
import {
  classifyPurity,
  extractCompletionVariants,
  extractReadSet,
  extractWriteSet,
  extractPerformSet,
} from '../../runtime/storage-program.js';
import { interpret } from '../../runtime/interpreter.js';
import { createInMemoryStorage } from '../../runtime/adapters/storage.js';

describe('VueAdapter functional handler', () => {
  let storage: ReturnType<typeof createInMemoryStorage>;

  beforeEach(() => {
    storage = createInMemoryStorage();
  });

  describe('normalize', () => {
    it('builds a valid StorageProgram', () => {
      const program = vueAdapterHandler.normalize({ adapter: 'test', props: 'test-props' });
      expect(program).toBeDefined();
      expect(program.instructions).toBeDefined();
      expect(Array.isArray(program.instructions)).toBe(true);
      expect(program.instructions.length).toBeGreaterThan(0);
    });

    it('has classifiable purity', () => {
      const program = vueAdapterHandler.normalize({ adapter: 'test', props: 'test-props' });
      if (!program?.instructions) return; // skip non-StorageProgram handlers
      const purity = classifyPurity(program);
      expect(['pure', 'read-only', 'read-write']).toContain(purity);
    });

    it('declares completion variants', () => {
      const program = vueAdapterHandler.normalize({ adapter: 'test', props: 'test-props' });
      if (!program?.instructions) return; // skip non-StorageProgram handlers
      const variants = program.effects?.completionVariants ?? extractCompletionVariants(program);
      expect(variants.size).toBeGreaterThan(0);
    });

    it('declares read and write sets', () => {
      const program = vueAdapterHandler.normalize({ adapter: 'test', props: 'test-props' });
      if (!program?.instructions) return; // skip non-StorageProgram handlers
      const reads = extractReadSet(program);
      const writes = extractWriteSet(program);
      const purity = classifyPurity(program);
      if (purity === 'read-only') {
        expect(reads.size).toBeGreaterThan(0);
      } else if (purity === 'read-write') {
        expect(writes.size).toBeGreaterThan(0);
      }
    });

    it('has trackable transport effects', () => {
      const program = vueAdapterHandler.normalize({ adapter: 'test', props: 'test-props' });
      if (!program?.instructions) return; // skip non-StorageProgram handlers
      const effects = extractPerformSet(program);
      expect(effects).toBeDefined();
    });

    it('executes without crashing', async () => {
      if (typeof vueAdapterHandler.normalize !== 'function') return;
      try {
        const result = await interpret(vueAdapterHandler.normalize({ adapter: 'test', props: 'test-props' }), storage);
        expect(result).toBeDefined();
        expect(result.variant).toBeDefined();
        expect(typeof result.variant).toBe('string');
      } catch (e) {
        // Handler may throw on invalid default inputs (e.g. JSON parse) — that's acceptable
        expect(e).toBeDefined();
      }
    });

  });

  describe('invariant examples', () => {
    it("normalize succeeds with valid props and fails with empty", async () => {
      const storage = createInMemoryStorage();
      const normalizeResult0 = await interpret(vueAdapterHandler.normalize({ adapter: {"type":"variable","name":"a"}, props: {"type":"literal","value":"{ \"onclick\": \"handler_1\", \"class\": \"btn\" }"} }), storage);
      expect(normalizeResult0.variant).toBe("ok");
      const adapter = normalizeResult0.output["adapter"];
      const normalized = normalizeResult0.output["normalized"];
      const thenResult0 = await interpret(vueAdapterHandler.normalize({ adapter: {"type":"variable","name":"a"}, props: {"type":"literal","value":""} }), storage);
      expect(thenResult0.variant).toBe("error");
    });

  });

  describe('state invariants (stateful PBT)', () => {
    it('always: normalized output uses Vue v-on event format', async () => {
      await fc.assert(
        fc.asyncProperty(
          fc.array(
            fc.oneof(
              fc.record({ action: fc.constant('normalize'), input: fc.record({ adapter: fc.string(), props: fc.string({ minLength: 1, maxLength: 50 }) }) }),
            ),
            { minLength: 1, maxLength: 5 },
          ),
          async (actionSequence) => {
            const storage = createInMemoryStorage();
            for (const step of actionSequence) {
              const actionFn = vueAdapterHandler[step.action];
              if (typeof actionFn === 'function') {
                try {
                  const program = actionFn.call(vueAdapterHandler, step.input as Record<string, unknown>);
                  const result = await interpret(program, storage);
                  expect(result.variant).toBeDefined();
                } catch { /* handler may throw on random inputs */ }
              }
            }
          },
        ),
        { numRuns: 50 },
      );
    });

    it('never: normalize produces output with raw DOM event names', async () => {
      await fc.assert(
        fc.asyncProperty(
          fc.array(
            fc.oneof(
              fc.record({ action: fc.constant('normalize'), input: fc.record({ adapter: fc.string(), props: fc.string({ minLength: 1, maxLength: 50 }) }) }),
            ),
            { minLength: 1, maxLength: 5 },
          ),
          async (actionSequence) => {
            const storage = createInMemoryStorage();
            for (const step of actionSequence) {
              const actionFn = vueAdapterHandler[step.action];
              if (typeof actionFn === 'function') {
                try {
                  const program = actionFn.call(vueAdapterHandler, step.input as Record<string, unknown>);
                  const result = await interpret(program, storage);
                  expect(result.variant).toBeDefined();
                  // Never: normalize produces output with raw DOM event names
                } catch { /* handler may throw on random inputs */ }
              }
            }
          },
        ),
        { numRuns: 50 },
      );
    });

  });

  describe('action contracts (PBT)', () => {
  });

});
